const xmlContent = $('Parse JSON and Extract SEC Document').first().json.rawXml;

// Extract all related persons
const relatedPersonsRegex = /<relatedPersonInfo>([\s\S]*?)<\/relatedPersonInfo>/g;
const personnel = [];

let match;
while ((match = relatedPersonsRegex.exec(xmlContent)) !== null) {
  const personXml = match[1];

  const firstName = personXml.match(/<firstName>(.*?)<\/firstName>/)?.[1];
  const lastName = personXml.match(/<lastName>(.*?)<\/lastName>/)?.[1];
  const clarification = personXml.match(/<relationshipClarification>(.*?)<\/relationshipClarification>/)?.[1];

  // Extract all relationships for this person
  const relationshipRegex = /<relationship>(.*?)<\/relationship>/g;
  const relationships = [];
  let relMatch;
  while ((relMatch = relationshipRegex.exec(personXml)) !== null) {
    relationships.push(relMatch[1]);
  }

  // Handle company entities vs individuals
  const name = firstName === '-' ? lastName : `${firstName} ${lastName}`;

  personnel.push({
    name: name,
    roles: relationships,
    clarification: clarification || null,
    type: firstName === '-' ? 'Entity' : 'Individual'
  });
}

return [{
  json: {
    keyPersonnel: personnel
  }
}];

const xmlContent = $('Parse JSON and Extract SEC Document').first().json.rawXml;

// Extract financial information
const totalOffering = xmlContent.match(/<totalOfferingAmount>(.*?)<\/totalOfferingAmount>/)?.[1];
const totalSold = xmlContent.match(/<totalAmountSold>(.*?)<\/totalAmountSold>/)?.[1];
const totalRemaining = xmlContent.match(/<totalRemaining>(.*?)<\/totalRemaining>/)?.[1];
const totalInvestors = xmlContent.match(/<totalNumberAlreadyInvested>(.*?)<\/totalNumberAlreadyInvested>/)?.[1];
const hasNonAccredited = xmlContent.match(/<hasNonAccreditedInvestors>(.*?)<\/hasNonAccreditedInvestors>/)?.[1];
const yetToOccur = xmlContent.match(/<yetToOccur>(.*?)<\/yetToOccur>/)?.[1];
const moreThanOneYear = xmlContent.match(/<moreThanOneYear>(.*?)<\/moreThanOneYear>/)?.[1];

// Extract exemptions
const exemptionRegex = /<item>(.*?)<\/item>/g;
const exemptions = [];
let exemptionMatch;
while ((exemptionMatch = exemptionRegex.exec(xmlContent)) !== null) {
  exemptions.push(exemptionMatch[1]);
}

// Format currency function
const formatCurrency = (amount) => {
  if (amount === 'Indefinite' || amount === '0' || !amount) {
    return amount === 'Indefinite' ? 'Indefinite' : '$0';
  }
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 0
  }).format(parseInt(amount));
};

return [{
  json: {
    offeringDetails: {
      totalOfferingAmount: totalOffering,
      totalAmountSold: formatCurrency(totalSold),
      totalRemaining: totalRemaining,
      numberOfInvestors: totalInvestors,
      allAccreditedInvestors: hasNonAccredited === 'false',
      exemptionsUsed: exemptions.map(e => {
        if (e === '06b') return 'Rule 506(b)';
        if (e === '3C') return 'Investment Company Act Section 3(c)';
        if (e === '3C.7') return 'Section 3(c)(7)';
        return e;
      }),
      saleStatus: yetToOccur === 'true' ? 'Not yet commenced' : 'Active',
      offeringDuration: moreThanOneYear === 'false' ? 'Less than one year' : 'More than one year'
    }
  }
}];

// Parse the input data structure
const inputData = $input.all()[0].json;
let docText;

const filingLinkTxt = $("Process Filings Batch").first().json;

// Handle different input formats
if (Array.isArray(inputData)) {
  docText = inputData[0].data;
} else if (inputData.data) {
  docText = inputData.data;
} else {
  docText = inputData.body || inputData;
}

// Extract basic document info
const xmlMatch = docText.match(/<XML>([\s\S]*?)<\/XML>/);
if (!xmlMatch) {
  throw new Error('No XML content found');
}

const xmlContent = xmlMatch[1];

return [{
  json: {
    rawXml: xmlContent,
    filingDate: docText.match(/FILED AS OF DATE:\s*(\d+)/)?.[1],
    accessionNumber: docText.match(/ACCESSION NUMBER:\s*([^\n]+)/)?.[1]?.trim(),
    submissionType: docText.match(/CONFORMED SUBMISSION TYPE:\s*([^\n]+)/)?.[1]?.trim(),
    filingLinkTxt: filingLinkTxt.filingLinkTxt
  }
}];

// Extract the entries array
const entries = $('Parse XML Feed').first().json.feed.entry;

// Map each entry to a flat object
return entries.map(entry => {
  // Best method: Extract CIK from title (in parentheses)
  const titleMatch = entry.title.match(/\((\d{10})\)/);
  const cikNumber = titleMatch ? titleMatch[1].replace(/^0+/, '') : '';

  // Get the HTML link
  const htmlLink = entry.link.href;

  // Convert to TXT link by:
  // 1. Removing "-index.htm" at the end
  // 2. Adding ".txt" extension
  const txtLink = htmlLink.replace('-index.htm', '.txt');

  return {
    cikNumber: cikNumber || '',
    title: entry.title,
    formType: entry.category.term,
    filingLinkHtml: htmlLink,
    filingLinkTxt: txtLink,
    updated: entry.updated,
    status: ""
  };
});

const xmlContent = $input.first().json.rawXml;

// Extract company details
const companyName = xmlContent.match(/<entityName>(.*?)<\/entityName>/)?.[1];
const cik = xmlContent.match(/<cik>(.*?)<\/cik>/)?.[1];
const street1 = xmlContent.match(/<street1>(.*?)<\/street1>/)?.[1];
const street2 = xmlContent.match(/<street2>(.*?)<\/street2>/)?.[1];
const city = xmlContent.match(/<city>(.*?)<\/city>/)?.[1];
const state = xmlContent.match(/<stateOrCountry>([^<]*)<\/stateOrCountry>/)?.[1];
const zipCode = xmlContent.match(/<zipCode>(.*?)<\/zipCode>/)?.[1];
const phone = xmlContent.match(/<issuerPhoneNumber>(.*?)<\/issuerPhoneNumber>/)?.[1];
const jurisdiction = xmlContent.match(/<jurisdictionOfInc>(.*?)<\/jurisdictionOfInc>/)?.[1];
const yearOfInc = xmlContent.match(/<value>(\d{4})<\/value>/)?.[1];
const entityType = xmlContent.match(/<entityType>(.*?)<\/entityType>/)?.[1];

// Extract fund-specific info
const industryGroup = xmlContent.match(/<industryGroupType>(.*?)<\/industryGroupType>/)?.[1];
const investmentFundType = xmlContent.match(/<investmentFundType>(.*?)<\/investmentFundType>/)?.[1];

// Build address
let address = street1;
if (street2) address += `, ${street2}`;
address += `, ${city}, ${state} ${zipCode}`;

return [{
  json: {
    companyInfo: {
      name: companyName,
      cik: cik,
      address: address,
      phone: phone,
      jurisdiction: jurisdiction,
      yearIncorporated: yearOfInc,
      entityType: entityType,
      industry: industryGroup,
      fundType: investmentFundType,
    }
  }
}];

const companyInfo = $('Parse Issuer Details').all()[0].json.companyInfo;
const personnel = $('Extract Key Personnel').all()[0].json.keyPersonnel;
const offering = $('Extract Offering Financial Details').all()[0].json.offeringDetails;
const docInfo = $('Parse JSON and Extract SEC Document').all()[0].json;

// Separate entities from individuals
const individuals = personnel.filter(p => p.type === 'Individual');
const entities = personnel.filter(p => p.type === 'Entity');

// Find key executive (prefer CEO, then any Executive Officer)
let keyExecutive = '';
let executiveRole = '';

if (individuals.length > 0) {
  // Look for CEO first
  const ceo = individuals.find(p => 
    p.roles.some(role => 
      role.toLowerCase().includes('chief executive') || 
      role.toLowerCase().includes('ceo')
    )
  );

  if (ceo) {
    keyExecutive = ceo.name;
    executiveRole = ceo.roles.find(role => 
      role.toLowerCase().includes('chief executive') || 
      role.toLowerCase().includes('ceo')
    ) || ceo.roles[0];
  } else {
    // If no CEO, take first Executive Officer
    const execOfficer = individuals.find(p => 
      p.roles.some(role => 
        role.toLowerCase().includes('executive officer')
      )
    );

    if (execOfficer) {
      keyExecutive = execOfficer.name;
      executiveRole = execOfficer.roles.find(role => 
        role.toLowerCase().includes('executive officer')
      ) || execOfficer.roles[0];
    } else {
      // If no Executive Officer, take first individual
      keyExecutive = individuals[0].name;
      executiveRole = individuals[0].roles[0] || '';
    }
  }
}

return [{
  json: {
    summary: {
      filingLinkText: docInfo.filingLinkTxt,
      companyName: companyInfo.name,
      keyExecutive: keyExecutive,
      executiveRole: executiveRole,      
      fundType: companyInfo.fundType,
      targetAmount: offering.totalOfferingAmount,
      amountRaised: offering.totalAmountSold,
      investorCount: offering.numberOfInvestors,
      saleStatus: offering.saleStatus,
      filingDate: docInfo.filingDate,
      exemptions: offering.exemptionsUsed
    },
    fullDetails: {
      company: companyInfo,
      executiveTeam: individuals,
      relatedEntities: entities,
      offering: offering,
      document: {
        filingLinkText: docInfo.filingLinkTxt,
        accessionNumber: docInfo.accessionNumber,
        submissionType: docInfo.submissionType,
        filingDate: docInfo.filingDate
      }
    }
  }
}];
